parameters.jsCode:
const raw = $input.first().json.text || '';
let plan;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  plan = match ? JSON.parse(match[0]) : null;
} catch(e) { plan = null; }

if (!plan || !plan.approved_features) {
  plan = { approved_features: ['FamilySize', 'IsAlone', 'TitleEncoded'], rationale: 'Default fallback features' };
}

// Pass through all upstream data
const upstream = $('P2: Clean Data').first().json;
return [{ json: { ...upstream, approved_features: plan.approved_features, feature_rationale: plan.rationale } }];

const upstream = $input.first().json;
const cleanData = JSON.parse(upstream.clean_data);

// Engineer features
const titleMap = { 'Mr': 1, 'Mrs': 2, 'Miss': 3, 'Master': 4, 'Dr': 5, 'Rev': 6 };

const engineered = cleanData.map(row => {
  const sibsp = parseFloat(row['SibSp']) || 0;
  const parch = parseFloat(row['Parch']) || 0;
  const familySize = sibsp + parch + 1;
  const isAlone = familySize === 1 ? 1 : 0;

  const name = row['Name'] || '';
  const titleMatch = name.match(/,\s*([A-Za-z]+)\./);
  const titleStr = titleMatch ? titleMatch[1] : 'Mr';
  const titleEnc = titleMap[titleStr] || 1;

  return {
    ...row,
    FamilySize: familySize,
    IsAlone: isAlone,
    TitleEncoded: titleEnc
  };
});

// Validate row count
if (engineered.length !== cleanData.length) {
  throw new Error(`Row count mismatch: ${cleanData.length} → ${engineered.length}`);
}

return [{ json: {
  strategy: upstream.strategy,
  clean_count: upstream.clean_count,
  feature_count: engineered.length,
  approved_features: upstream.approved_features,
  engineered_data: JSON.stringify(engineered)
}}];

const upstream = $('P3: Engineer Features').first().json;
const p3data = $('P3: Engineer Features').first().json;

// Parse engineered data once
const allData = JSON.parse(p3data.engineered_data);
const targetVar = p3data.strategy.target_variable;

// Feature columns to use
const featureCols = ['Pclass', 'Age', 'SibSp', 'Parch', 'Fare', 'Sex_enc', 'Embarked_enc', 'FamilySize', 'IsAlone', 'TitleEncoded'];

// Build X and y
const X = allData.map(row => featureCols.map(f => {
  const v = parseFloat(row[f]);
  return isNaN(v) ? 0 : v;
}));
const y = allData.map(row => parseFloat(row[targetVar]) || 0);

// Train/test split (80/20)
const splitIdx = Math.floor(X.length * 0.8);
const Xtrain = X.slice(0, splitIdx);
const ytrain = y.slice(0, splitIdx);
const Xtest = X.slice(splitIdx);
const ytest = y.slice(splitIdx);

return [{ json: {
  strategy: p3data.strategy,
  featureCols,
  Xtrain: JSON.stringify(Xtrain),
  ytrain: JSON.stringify(ytrain),
  Xtest: JSON.stringify(Xtest),
  ytest: JSON.stringify(ytest),
  train_size: Xtrain.length,
  test_size: Xtest.length
}}];

const setup = $input.first().json;
const Xtrain = JSON.parse(setup.Xtrain);
const ytrain = JSON.parse(setup.ytrain);
const Xtest = JSON.parse(setup.Xtest);
const ytest = JSON.parse(setup.ytest);

// --- Helpers ---
function dot(a, b) { return a.reduce((s, v, i) => s + v * b[i], 0); }
function sigmoid(z) { return 1 / (1 + Math.exp(-Math.max(-500, Math.min(500, z)))); }

function calcMetrics(ypred, ytrue) {
  let tp=0, fp=0, fn=0, tn=0;
  for (let i=0; i<ytrue.length; i++) {
    if (ypred[i]===1 && ytrue[i]===1) tp++;
    else if (ypred[i]===1 && ytrue[i]===0) fp++;
    else if (ypred[i]===0 && ytrue[i]===1) fn++;
    else tn++;
  }
  const prec = tp+fp>0 ? tp/(tp+fp) : 0;
  const rec = tp+fn>0 ? tp/(tp+fn) : 0;
  const f1 = prec+rec>0 ? 2*prec*rec/(prec+rec) : 0;
  const acc = (tp+tn)/ytrue.length;
  return { accuracy: Math.round(acc*1000)/1000, precision: Math.round(prec*1000)/1000, recall: Math.round(rec*1000)/1000, f1_score: Math.round(f1*1000)/1000 };
}

// --- 1. Logistic Regression (gradient descent) ---
function trainLogReg(X, y, lr=0.01, epochs=200) {
  const n = X[0].length;
  let w = new Array(n).fill(0);
  let b = 0;
  for (let e=0; e<epochs; e++) {
    let dw = new Array(n).fill(0), db = 0;
    for (let i=0; i<X.length; i++) {
      const pred = sigmoid(dot(X[i], w) + b);
      const err = pred - y[i];
      for (let j=0; j<n; j++) dw[j] += err * X[i][j];
      db += err;
    }
    for (let j=0; j<n; j++) w[j] -= lr * dw[j] / X.length;
    b -= lr * db / X.length;
  }
  return { w, b };
}
const lrModel = trainLogReg(Xtrain, ytrain);
const lrPred = Xtest.map(x => sigmoid(dot(x, lrModel.w) + lrModel.b) >= 0.5 ? 1 : 0);
const lrMetrics = calcMetrics(lrPred, ytest);

// --- 2. Random Forest (bagged decision stumps) ---
function trainStump(X, y, featureIdx) {
  let bestThresh = 0, bestGini = 1, bestDir = 1;
  const vals = X.map(row => row[featureIdx]).sort((a,b) => a-b);
  const thresholds = vals.filter((v,i) => i===0 || v !== vals[i-1]);
  for (const t of thresholds) {
    for (const dir of [1, -1]) {
      const pred = X.map(row => (dir*(row[featureIdx]-t) >= 0) ? 1 : 0);
      let tp=0,tn=0,fp=0,fn=0;
      pred.forEach((p,i) => { if(p===1&&y[i]===1)tp++; else if(p===0&&y[i]===0)tn++; else if(p===1)fp++; else fn++; });
      const n1=tp+fp, n0=tn+fn, tot=X.length;
      const g1=n1>0?1-Math.pow(tp/n1,2)-Math.pow(fp/n1,2):0;
      const g0=n0>0?1-Math.pow(tn/n0,2)-Math.pow(fn/n0,2):0;
      const gini=(n1*g1+n0*g0)/tot;
      if(gini<bestGini){bestGini=gini;bestThresh=t;bestDir=dir;}
    }
  }
  return { featureIdx, threshold: bestThresh, direction: bestDir };
}

const numFeatures = Xtrain[0].length;
const trees = [];
for (let t=0; t<10; t++) {
  const bagSize = Math.floor(Xtrain.length * 0.8);
  const bagIdx = Array.from({length: bagSize}, () => Math.floor(Math.random()*Xtrain.length));
  const Xbag = bagIdx.map(i => Xtrain[i]);
  const ybag = bagIdx.map(i => ytrain[i]);
  const fIdx = Math.floor(Math.random() * numFeatures);
  trees.push(trainStump(Xbag, ybag, fIdx));
}
const rfPred = Xtest.map(x => {
  const votes = trees.map(s => (s.direction*(x[s.featureIdx]-s.threshold) >= 0) ? 1 : 0);
  return votes.reduce((a,b)=>a+b,0) >= trees.length/2 ? 1 : 0;
});
const rfMetrics = calcMetrics(rfPred, ytest);

// --- 3. XGBoost Stumps (gradient boosting) ---
function xgbBoost(X, y, nRounds=20, lr=0.3) {
  let F = new Array(X.length).fill(0);
  const stumps = [];
  for (let r=0; r<nRounds; r++) {
    const residuals = F.map((f,i) => y[i] - sigmoid(f));
    let bestStump = null, bestCorr = -Infinity;
    for (let fi=0; fi<X[0].length; fi++) {
      const vals = [...new Set(X.map(row => row[fi]))].sort((a,b)=>a-b);
      for (const t of vals) {
        const pred = X.map(row => row[fi] >= t ? 1 : -1);
        const corr = pred.reduce((s,p,i) => s + p*residuals[i], 0);
        if (Math.abs(corr) > bestCorr) { bestCorr = Math.abs(corr); bestStump = {fi, t, dir: corr>0?1:-1}; }
      }
    }
    if (!bestStump) break;
    stumps.push(bestStump);
    F = F.map((f,i) => f + lr * bestStump.dir * (X[i][bestStump.fi] >= bestStump.t ? 1 : -1));
  }
  return { stumps, F_train: F };
}
const xgbModel = xgbBoost(Xtrain, ytrain);
const xgbPredF = Xtest.map(x => {
  let f = 0;
  for (const s of xgbModel.stumps) f += 0.3 * s.dir * (x[s.fi] >= s.t ? 1 : -1);
  return f;
});
const xgbPred = xgbPredF.map(f => sigmoid(f) >= 0.5 ? 1 : 0);
const xgbMetrics = calcMetrics(xgbPred, ytest);

const results = [
  { algorithm: 'LogisticRegression', ...lrMetrics },
  { algorithm: 'RandomForest', ...rfMetrics },
  { algorithm: 'XGBoost', ...xgbMetrics }
];

return [{ json: {
  strategy: setup.strategy,
  train_size: setup.train_size,
  test_size: setup.test_size,
  model_results: results,
  model_results_str: JSON.stringify(results)
}}];

