const raw = $input.first().json.text || '';
let verdict;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  verdict = match ? JSON.parse(match[0]) : null;
} catch(e) { verdict = null; }

const upstream = $('P4: Train All Models').first().json;
const results = upstream.model_results;

