  // Fallback: pick highest f1
  const best = results.reduce((a,b) => b.f1_score > a.f1_score ? b : a);
  verdict = { winner: best.algorithm, f1_score: best.f1_score, accuracy: best.accuracy, justification: 'Selected by highest F1 score' };
}

return [{ json: {
