const csvText = $input.first().json.data || '';
const strategy = $('P1: Parse Strategy').first().json;
const targetVar = strategy.target_variable;

if (!csvText) throw new Error('No CSV data received');

// Proper CSV parser that handles quoted fields with commas
function parseCSVLine(line) {
  const result = [];
  let cur = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQuotes && line[i+1] === '"') { cur += '"'; i++; }
      else inQuotes = !inQuotes;
    } else if (ch === ',' && !inQuotes) {
      result.push(cur.trim());
      cur = '';
    } else {
      cur += ch;
    }
  }
  result.push(cur.trim());
  return result;
}

const lines = csvText.trim().split('\n');
const headers = parseCSVLine(lines[0]);
const rows = [];
for (let i = 1; i < lines.length; i++) {
  if (!lines[i].trim()) continue;
  const vals = parseCSVLine(lines[i]);
  if (vals.length >= headers.length - 1) {
    const row = {};
    headers.forEach((h, idx) => { row[h] = vals[idx] || ''; });
    rows.push(row);
  }
}

// Drop rows with missing target
const cleaned = rows.filter(r => r[targetVar] !== '' && r[targetVar] !== undefined);

// Numeric conversion
const numericFields = ['Age', 'Fare', 'SibSp', 'Parch', 'Pclass', 'PassengerId', targetVar];
cleaned.forEach(row => {
  numericFields.forEach(f => {
    if (row[f] !== undefined && row[f] !== '') {
      const n = parseFloat(row[f]);
      if (!isNaN(n)) row[f] = n;
    }
  });
  if (typeof row['Age'] !== 'number' || isNaN(row['Age'])) row['Age'] = 29;
  row['Sex_enc'] = row['Sex'] === 'male' ? 0 : row['Sex'] === 'female' ? 1 : -1;
  const embMap = { 'S': 0, 'C': 1, 'Q': 2 };
  row['Embarked_enc'] = embMap[row['Embarked']] !== undefined ? embMap[row['Embarked']] : 0;
});

return [{ json: {
  strategy,
  original_count: rows.length,
  clean_count: cleaned.length,
  headers,
  clean_data: JSON.stringify(cleaned)
}}];
